import React, { useEffect, useState, useContext } from 'react';
import api from '../api/axiosConfig';
import { AuthContext } from '../context/AuthContext';
import ReactMarkdown from 'react-markdown'; // 1. IMPORT MARKDOWN
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, Hash, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { token } = useContext(AuthContext);
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const safeParse = (data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) { return []; }
  };

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("PERMANENT_WIPE: Proceed?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED");
    } catch (err) { toast.error("WIPE_FAILURE"); }
  };

  const handleDownload = async (item) => {
    try {
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) { toast.error("EXPORT_FAILED"); }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <div style={headerRow}>
        <h2 style={headerStyle}><Archive size={22} color="var(--accent-primary)"/> VAULT_HISTORY</h2>
        <div style={vaultBadge}><BarChart3 size={12} /> {history.length} NODES</div>
      </div>
      
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={cardMeta}>
              <div style={{ display: 'flex', gap: '15px' }}>
                <span style={dateTag}><Calendar size={11}/> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={11}/> RISK: {item.risk_score}</span>
              </div>
              <div style={cardActions}>
                <button onClick={() => setSelectedItem(item)} style={iconBtn}><Eye size={17}/></button>
                <button onClick={() => handleDownload(item)} style={iconBtn}><Download size={17}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn}><Trash2 size={17}/></button>
              </div>
            </div>

            <h4 style={titleStyle}>{item.goal}</h4>

            {/* 2. RENDER SUMMARY AS MARKDOWN */}
            <div style={sectionBlock}>
              <p style={labelSmall}><AlignLeft size={10} /> MARKET_SUMMARY</p>
              <div className="markdown-vault">
                <ReactMarkdown>{item.summary}</ReactMarkdown>
              </div>
            </div>

            <div style={sectionBlock}>
              <p style={labelSmall}><Hash size={10} /> ALLOCATIONS</p>
              <div style={tickerGrid}>
                 {safeParse(item.holdings).map((t, i) => <span key={i} style={tickerBadge}>{t}</span>)}
              </div>
            </div>
          </div>
        ))}
      </div>

      {selectedItem && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={20}/></button>
            </div>
            <div style={modalBody}>
              <h3 style={modalTitle}>{selectedItem.goal}</h3>
              
              <div style={modalSection}>
                <p style={modalLabel}>STRATEGIC_THESIS</p>
                <div className="markdown-vault">
                    <ReactMarkdown>{selectedItem.summary}</ReactMarkdown>
                </div>
              </div>

              <div style={modalSection}>
                <p style={modalLabel}>AGENTIC_RATIONALE</p>
                {/* 3. RENDER RATIONALE AS MARKDOWN */}
                <div className="markdown-vault rationale-area">
                    <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
